mapper.select:
select e.*,
       c.course_name,
       u.real_name as student_name
from course_evaluation e
         left join course_info c on e.course_id = c.id
         left join sys_user u on e.student_id = u.id


        and e.schedule_id = #{scheduleId}


        and e.student_id = #{studentId}


        and e.teacher_id = #{teacherId}


order by e.id desc
